#include <stdio.h>

int main(void) {
    double celsius, offset, corrected, fahrenheit;

    scanf("%lf %lf", &celsius, &offset);

    corrected = celsius - offset;
    fahrenheit = (corrected * 9.0 / 5.0) + 32.0;

    printf("%.2f\n", fahrenheit);

    return 0;
}

#include <stdio.h>
#include <math.h>

int main(void) {
    double principal, rate_percent, time, amount;
    int n;

    scanf("%lf %lf %d %lf", &principal, &rate_percent, &n, &time);

    double rate = rate_percent / 100.0;
    amount = principal * pow(1.0 + rate / n, n * time);

    printf("%.2f\n", amount);

    return 0;
}

#include <stdio.h>

int main(void) {
    double miles, feet, inches, centimeters;

    scanf("%lf", &miles);

    feet = miles * 5280.0;
    inches = feet * 12.0;
    centimeters = inches * 2.54;

    printf("%.1f\n", centimeters);

    return 0;
}

#include <stdio.h>

int main(void) {
    int score1, score2, score3;
    double weight1, weight2, weight3;
    double weighted_sum, total_weight, average;

    scanf("%d %lf %d %lf %d %lf", &score1, &weight1, &score2, &weight2, &score3, &weight3);

    weighted_sum = (score1 * weight1) + (score2 * weight2) + (score3 * weight3);
    total_weight = weight1 + weight2 + weight3;
    average = weighted_sum / total_weight;

    printf("%.2f\n", average);

    return 0;
}

#include <stdio.h>

int main(void) {
    double cost, selling_price;
    double markup, profit_margin;

    scanf("%lf %lf", &cost, &selling_price);

    markup = ((selling_price - cost) / cost) * 100.0;
    profit_margin = ((selling_price - cost) / selling_price) * 100.0;

    printf("%.1f\n", markup);
    printf("%.1f\n", profit_margin);

    return 0;
}

#include <stdio.h>

int main(void) {
    double speed1, time1, speed2, time2;
    double distance1, distance2, total_distance;

    scanf("%lf %lf %lf %lf", &speed1, &time1, &speed2, &time2);

    distance1 = speed1 * time1;
    distance2 = speed2 * time2;
    total_distance = distance1 + distance2;

    printf("%.1f\n", total_distance);

    return 0;
}

#include <stdio.h>

int main(void) {
    double source_amount, exchange_rate, fee_percent;
    int flag;
    double fee, after_fee, target_amount;

    scanf("%lf %lf %lf %d", &source_amount, &exchange_rate, &fee_percent, &flag);

    if (flag == 0) {
        fee = source_amount * (fee_percent / 100.0);
        after_fee = source_amount - fee;
        target_amount = after_fee * exchange_rate;
    } else {
        target_amount = source_amount * exchange_rate;
        fee = target_amount * (fee_percent / 100.0);
        target_amount = target_amount - fee;
    }

    printf("%.2f\n", target_amount);

    return 0;
}

#include <stdio.h>

int main(void) {
    double height, weight, bmi;
    int category;

    scanf("%lf %lf", &height, &weight);

    bmi = weight / (height * height);

    category = 1 + (int)(bmi >= 18.5) + (int)(bmi >= 25.0) + (int)(bmi >= 30.0);

    printf("%.1f\n", bmi);
    printf("%d\n", category);

    return 0;
}

#include <stdio.h>

int main(void) {
    double old_value, new_value;
    double percent_change;

    scanf("%lf %lf", &old_value, &new_value);

    percent_change = ((new_value - old_value) / old_value) * 100.0;

    printf("%.2f\n", percent_change);

    return 0;
}

#include <stdio.h>

int main(void) {
    double original_price, discount_percent, tax_percent;
    double discounted_price, final_price;

    scanf("%lf %lf %lf", &original_price, &discount_percent, &tax_percent);

    discounted_price = original_price * (1.0 - discount_percent / 100.0);
    final_price = discounted_price * (1.0 + tax_percent / 100.0);

    printf("%.2f\n", final_price);

    return 0;
}
